using System.Threading.Tasks;
using Azure.Core;
using Azure.Provisioning.Tests;
using NUnit.Framework;

namespace Azure.Provisioning.ServiceNetworking.Tests;

public class BasicServiceNetworkingTests
{
    internal static Trycep CreateTrafficControllerTest()
    {
        return new Trycep().Define(
            ctx =>
            {
                #region Snippet:ServiceNetworkingBasic
                Infrastructure infra = new();

                TrafficController controller =
                    new(nameof(controller), TrafficController.ResourceVersions.V2025_01_01)
                    {
                        Tags = { ["environment"] = "test" },
                    };
                infra.Add(controller);

                TrafficControllerFrontend frontend =
                    new(nameof(frontend), TrafficControllerFrontend.ResourceVersions.V2025_01_01)
                    {
                        Parent = controller,
                    };
                infra.Add(frontend);

                TrafficControllerAssociation association =
                    new(nameof(association), TrafficControllerAssociation.ResourceVersions.V2025_01_01)
                    {
                        Parent = controller,
                        AssociationType = TrafficControllerAssociationType.Subnets,
                        SubnetId = new ResourceIdentifier("/subscriptions/00000000-0000-0000-0000-000000000000/resourceGroups/myRg/providers/Microsoft.Network/virtualNetworks/myVnet/subnets/mySubnet"),
                    };
                infra.Add(association);
                #endregion

                return infra;
            });
    }

    [Test]
    public async Task CreateTrafficController()
    {
        await using Trycep test = CreateTrafficControllerTest();
        test.Compare(
            """
            @description('The location for the resource(s) to be deployed.')
            param location string = resourceGroup().location

            resource controller 'Microsoft.ServiceNetworking/trafficControllers@2025-01-01' = {
              name: take('controller-${uniqueString(resourceGroup().id)}', 24)
              tags: {
                environment: 'test'
              }
              location: location
            }

            resource frontend 'Microsoft.ServiceNetworking/trafficControllers/frontends@2025-01-01' = {
              name: take('frontend-${uniqueString(resourceGroup().id)}', 24)
              location: location
              parent: controller
            }

            resource association 'Microsoft.ServiceNetworking/trafficControllers/associations@2025-01-01' = {
              name: take('association-${uniqueString(resourceGroup().id)}', 24)
              location: location
              properties: {
                associationType: 'subnets'
                subnet: {
                  id: '/subscriptions/00000000-0000-0000-0000-000000000000/resourceGroups/myRg/providers/Microsoft.Network/virtualNetworks/myVnet/subnets/mySubnet'
                }
              }
              parent: controller
            }
            """);
    }
}

# Azure Provisioning KeyVault client library for .NET

Azure.Provisioning.KeyVault simplifies declarative resource provisioning in .NET.

## Getting started

### Install the package

Install the client library for .NET with [NuGet](https://www.nuget.org/ ):

```dotnetcli
dotnet add package Azure.Provisioning.KeyVault
```

### Prerequisites

> You must have an [Azure subscription](https://azure.microsoft.com/free/dotnet/).

### Authenticate the Client

## Key concepts

This library allows you to specify your infrastructure in a declarative style using dotnet.  You can then use azd to deploy your infrastructure to Azure directly without needing to write or maintain bicep or arm templates.

## Examples

### Create a Basic Key Vault With Secret

This example demonstrates how to create a Key Vault and store a secret, based on the [Azure quickstart template](https://github.com/Azure/azure-quickstart-templates/blob/master/quickstarts/microsoft.keyvault/key-vault-create/main.bicep).

```C# Snippet:KeyVaultBasic
Infrastructure infra = new();

ProvisioningParameter skuName =
    new(nameof(skuName), typeof(string))
    {
        Value = KeyVaultSkuName.Standard,
        Description = "Vault type"
    };
infra.Add(skuName);

ProvisioningParameter secretValue =
    new(nameof(secretValue), typeof(string))
    {
        Description = "Specifies the value of the secret that you want to create.",
        IsSecure = true
    };
infra.Add(secretValue);

ProvisioningParameter objectId =
    new(nameof(objectId), typeof(string))
    {
        Description = "Specifies the object ID of a user, service principal or security group in the Azure Active Directory tenant for the vault."
    };
infra.Add(objectId);

ProvisioningVariable tenantId =
    new(nameof(tenantId), typeof(string))
    {
        Value = BicepFunction.GetSubscription().TenantId
    };
infra.Add(tenantId);

KeyVaultService kv =
    new(nameof(kv), KeyVaultService.ResourceVersions.V2023_07_01)
    {
        Properties =
            new KeyVaultProperties
            {
                Sku = new KeyVaultSku { Name = skuName, Family = KeyVaultSkuFamily.A, },
                TenantId = tenantId,
                EnableSoftDelete = true,
                SoftDeleteRetentionInDays = 90,
                AccessPolicies =
                {
                    new KeyVaultAccessPolicy
                    {
                        ObjectId = objectId,
                        TenantId = tenantId,
                        Permissions =
                            new IdentityAccessPermissions
                            {
                                Keys = { IdentityAccessKeyPermission.List },
                                Secrets = { IdentityAccessSecretPermission.List }
                            }
                    }
                },
                NetworkRuleSet =
                    new KeyVaultNetworkRuleSet
                    {
                        DefaultAction = KeyVaultNetworkRuleAction.Allow,
                        Bypass = KeyVaultNetworkRuleBypassOption.AzureServices
                    }
            }
    };
infra.Add(kv);

KeyVaultSecret secret =
    new(nameof(secret), KeyVaultSecret.ResourceVersions.V2023_07_01)
    {
        Parent = kv,
        Name = "myDarkNecessities",
        Properties = new SecretProperties { Value = secretValue }
    };
infra.Add(secret);

infra.Add(new ProvisioningOutput("name", typeof(string)) { Value = kv.Name });
infra.Add(new ProvisioningOutput("resourceId", typeof(string)) { Value = kv.Id });
infra.Add(new ProvisioningOutput("vaultUri", typeof(string)) { Value = kv.Properties.VaultUri });
```

